"""Plugin discovery and loading system."""
import importlib.util
import logging
from pathlib import Path
from typing import Any, Callable, Dict, List, Protocol

logger = logging.getLogger(__name__)


class Plugin(Protocol):
    name: str
    def execute(self, **kwargs: Any) -> Any: ...


class PluginManager:
    def __init__(self, plugin_dir: str):
        self.plugin_dir = Path(plugin_dir)
        self._plugins: Dict[str, Plugin] = {}

    def register(self, plugin: Plugin) -> None:
        """Register a plugin instance."""
        self._plugins[plugin.name] = plugin
        logger.info("Registered plugin: %s", plugin.name)

    def discover_and_load(self) -> int:
        """Discover and load all plugins. Returns count loaded."""
        if not self.plugin_dir.exists():
            logger.warning("Plugin directory not found: %s", self.plugin_dir)
            return 0
        count = 0
        for path in sorted(self.plugin_dir.glob("*.py")):
            if path.name.startswith("_"):
                continue
            try:
                self._load_module(path)
                count += 1
            except Exception as e:
                logger.error("Failed to load %s: %s", path.name, e)
        return count

    def _load_module(self, path: Path) -> None:
        spec = importlib.util.spec_from_file_location(
            f"plugin_{path.stem}", path
        )
        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)
        if hasattr(module, "register"):
            module.register(self)

    def get_plugin(self, name: str) -> Plugin:
        if name not in self._plugins:
            raise KeyError(f"Plugin not found: {name}")
        return self._plugins[name]

    def list_plugins(self) -> List[str]:
        return list(self._plugins.keys())
